CREATE TABLE `users` (
    `id` INT PRIMARY KEY AUTO_INCREMENT,
    `name` TEXT,
    `email` TEXT,
    `password` TEXT,
    `phone` TEXT,
    `referral_code` TEXT,
    `referred_by` INT,
    `role` TEXT,
    `status` TEXT,
    `permissions` TEXT,
    `is_super_admin` TINYINT(1),
    `otp_code` TEXT,
    `otp_expiry` TIMESTAMP,
    `created_at` TIMESTAMP,
    `activation_date` DATE,
    `manual_referral_updated` TINYINT(1),
    `city` TEXT,
    `wallet_balance` DECIMAL(15,2),
    `bank_name` TEXT,
    `account_number` TEXT,
    `ifsc` TEXT,
    `branch` TEXT,
    `state` TEXT,
    `coins` INT
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

